export class TabsContentState {
	static create(opts: TabsContentStateOpts) {
		return new TabsContentState(opts, TabsRootContext.get());
	}
	readonly opts: TabsContentStateOpts;
	readonly root: TabsRootState;
	readonly attachment: RefAttachment;
	readonly #isActive = $derived.by(
		() => this.root.opts.value.current === this.opts.value.current
	);
	readonly #ariaLabelledBy = $derived.by(() =>
		this.root.valueToTriggerId.get(this.opts.value.current)
	);

	constructor(opts: TabsContentStateOpts, root: TabsRootState) {
		this.opts = opts;
		this.root = root;
		this.attachment = attachRef(opts.ref);
		watch([() => this.opts.id.current, () => this.opts.value.current], ([id, value]) => {
			return this.root.registerContent(id, value);
		});
	}

	readonly props = $derived.by(
		() =>
			({
				id: this.opts.id.current,
				role: "tabpanel",
				hidden: boolToTrueOrUndef(!this.#isActive),
				tabindex: 0,
				"data-value": this.opts.value.current,
				"data-state": getTabDataState(this.#isActive),
				"aria-labelledby": this.#ariaLabelledBy,
				"data-orientation": this.root.opts.orientation.current,
				[tabsAttrs.content]: "",
				...this.attachment,
			}) as const
	);
}

export function link(node: HTMLElement, opts?: LinkActionInternalOpts | string): {
    update(updated?: LinkActionInternalOpts | string): void
    destroy(): void
} {
    let currentOpts = linkOpts(opts)

    // Only apply to <a> tags
    if (!node || !node.tagName || node.tagName.toLowerCase() != 'a') {
        throw Error('Action "link" can only be used with <a> tags')
    }

    // Set initial href
    updateLinkHref(node, currentOpts)

    // Add click handler once, using currentOpts reference
    const clickHandler = (event: MouseEvent): void => {
        event.preventDefault()
        if (!currentOpts.disabled) {
            const target = event.currentTarget as HTMLElement | null
            const href = target ? target.getAttribute('href') : null
            if (href) {
                scrollstateHistoryHandler(href)
            }
        }
    }
    node.addEventListener('click', clickHandler)

    return {
        update(updated?: LinkActionInternalOpts | string): void {
            currentOpts = linkOpts(updated)
            updateLinkHref(node, currentOpts)
        },
        destroy(): void {
            node.removeEventListener('click', clickHandler)
        }
    }
}

const content = makeElement(name('content'), {
	stores: [value, disabled, forceVisible],
	returned: ([$value, $disabled, $forceVisible]) => {
		return (props: AccordionItemProps) => {
			const { value: itemValue } = parseItemProps(props);
			const selected = isSelected(itemValue, $value);
			const isVisible = selected || $forceVisible;
			return {
				'data-state': selected ? 'open' : 'closed',
				'data-disabled': disabledAttr($disabled),
				'data-value': itemValue,
				hidden: isVisible ? undefined : true,
				style: isVisible ? undefined : styleToString({ display: 'none' }),
			} as const;
		};
	},
	action: (node: HTMLElement) => {
		tick().then(() => {
			const contentId = generateId();
			const triggerId = generateId();

			const parentTrigger = document.querySelector(
				`${selector('trigger')}, [data-value="${node.dataset.value}"]`
			);
			if (!isHTMLElement(parentTrigger)) return;

			node.id = contentId;
			parentTrigger.setAttribute('aria-controls', contentId);
			parentTrigger.id = triggerId;
		});
	},
});

function setupIntersectionObserver() {
  if (!browser) return { disconnect: () => {} };

  const root = scrollContainer ? document.querySelector(scrollContainer) : null;
  if (scrollContainer && !root) {
    console.warn("ScrollSpy: Scroll container not found:", scrollContainer);
  }

  const rootMargin = `-${offset}px 0px ${ROOT_MARGIN_BOTTOM} 0px`;
  // Use threshold range 0.0 → 1.0 in 0.1 steps for smooth updates with better performance
  const thresholds = Array.from({ length: 11 }, (_, i) => i / 10);

  const observer = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        const id = entry.target.id;
        if (entry.isIntersecting) {
          intersectingSections.set(id, entry);
        } else {
          intersectingSections.delete(id);
        }
      });
      updateActiveSection();
    },
    {
      root,
      rootMargin,
      threshold: thresholds
    }
  );

  items.forEach((item) => {
    const element = document.getElementById(item.id);
    if (element) observer.observe(element);
    else console.warn(`ScrollSpy: Section with id "${item.id}" not found in DOM`);
  });

  return observer;
}

function handleKeyResize(e: KeyboardEvent, index: number) {
  if (!container) return;
  if (index < 0 || index + 1 >= sizes.length) return;

  const isHorizontal = currentDirection === "horizontal";
  const increaseKeys = isHorizontal ? ["ArrowRight"] : ["ArrowDown"];
  const decreaseKeys = isHorizontal ? ["ArrowLeft"] : ["ArrowUp"];

  const containerSize = isHorizontal ? container.offsetWidth : container.offsetHeight;
  if (containerSize < 1) return;

  const minPercent = (minSize / containerSize) * 100;
  const total = sizes[index] + sizes[index + 1];

  let handled = false;

  if (increaseKeys.includes(e.key)) {
    const targetSize = sizes[index] + keyboardStep;
    handled = clampPaneSizes(index, targetSize, minPercent, total);
  } else if (decreaseKeys.includes(e.key)) {
    const targetSize = sizes[index] - keyboardStep;
    handled = clampPaneSizes(index, targetSize, minPercent, total);
  } else if (e.key === "Enter" || e.key === " ") {
    // Reset to equal sizes
    const equal = 100 / registeredPanes;
    sizes = sizes.map(() => equal);
    handled = true;
  }

  if (handled) {
    e.preventDefault();
  }
}

async function onintrostart(ev: CustomEvent & { currentTarget: HTMLDialogElement }) {
