function handleScroll() {
  if (!browser || !navElement || !sticky || !scrollElement) return;

  const container = scrollElement instanceof Window ? window : scrollElement;
  const isWindow = container === window;

  const scrollPosition = isWindow ? window.scrollY : (container as HTMLElement).scrollTop; // Type assertion here

  isSticky = scrollPosition > 0;
  updateActiveSection();
}

$effect(() => {
  if (!browser) return;

  if (scrollContainer) {
    const container = document.querySelector(scrollContainer);
    if (container instanceof HTMLElement) scrollElement = container;
    else {
      console.warn("ScrollSpy: Scroll container not found:", scrollContainer);
      scrollElement = window;
    }
  } else {
    scrollElement = window;
  }

  const observer = setupIntersectionObserver();

  const container = scrollElement instanceof Window ? window : scrollElement;
  container.addEventListener("scroll", handleScroll, { passive: true });
  handleScroll();

  return () => {
    observer.disconnect();
    container.removeEventListener("scroll", handleScroll);
  };
});

export function normalizeUrl(url) {
	url = new URL(url, 'a://a');

	const is_route_resolution = has_resolution_suffix(url.pathname);
	const is_data_request = has_data_suffix(url.pathname);
	const has_trailing_slash = url.pathname !== '/' && url.pathname.endsWith('/');

	if (is_route_resolution) {
		url.pathname = strip_resolution_suffix(url.pathname);
	} else if (is_data_request) {
		url.pathname = strip_data_suffix(url.pathname);
	} else if (has_trailing_slash) {
		url.pathname = url.pathname.slice(0, -1);
	}

	return {
		url,
		wasNormalized: is_data_request || is_route_resolution || has_trailing_slash,
		denormalize: (new_url = url) => {
			new_url = new URL(new_url, url);
			if (is_route_resolution) {
				new_url.pathname = add_resolution_suffix(new_url.pathname);
			} else if (is_data_request) {
				new_url.pathname = add_data_suffix(new_url.pathname);
			} else if (has_trailing_slash && !new_url.pathname.endsWith('/')) {
				new_url.pathname += '/';
			}
			return new_url;
		}
	};
}

function derive_remote_function_event(event, state, allow_cookies) {
	return {
		event: {
			...event,
			setHeaders: () => {
				throw new Error('setHeaders is not allowed in remote functions');
			},
			cookies: {
				...event.cookies,
				set: (name, value, opts) => {
					if (!allow_cookies) {
						throw new Error('Cannot set cookies in `query` or `prerender` functions');
					}

					if (opts.path && !opts.path.startsWith('/')) {
						throw new Error('Cookies set in remote functions must have an absolute path');
					}

					return event.cookies.set(name, value, opts);
				},
				delete: (name, opts) => {
					if (!allow_cookies) {
						throw new Error('Cannot delete cookies in `query` or `prerender` functions');
					}

					if (opts.path && !opts.path.startsWith('/')) {
						throw new Error('Cookies deleted in remote functions must have an absolute path');
					}

					return event.cookies.delete(name, opts);
				}
			}
		},
		state: {
			...state,
			is_in_remote_function: true
		}
	};
}

function wrapPreprocessors(preprocessors: PreprocessorGroup | PreprocessorGroup[] = []) {
    preprocessors = Array.isArray(preprocessors) ? preprocessors : [preprocessors];
    return preprocessors.map((preprocessor: any) => {
        const wrappedPreprocessor: PreprocessorGroup = { markup: preprocessor.markup };

        if (preprocessor.script) {
            wrappedPreprocessor.script = async (args: any) => {
                try {
                    return await preprocessor.script!(args);
                } catch (e: any) {
                    e.__source = TranspileErrorSource.Script;
                    throw e;
                }
            };
        }

        if (preprocessor.style) {
            wrappedPreprocessor.style = async (args: any) => {
                try {
                    return await preprocessor.style!(args);
                } catch (e: any) {
                    e.__source = TranspileErrorSource.Style;
                    throw e;
                }
            };
        }

        return wrappedPreprocessor;
    });
}

private updateDocInfo() {
    this.html = parseHtml(this.content);
    const update = (config: SvelteConfig | undefined) => {
        const scriptTags = extractScriptTags(this.content, this.html);
        this.config = config;
        this.scriptInfo = this.addDefaultLanguage(config, scriptTags?.script || null, 'script');
        this.moduleScriptInfo = this.addDefaultLanguage(
            config,
            scriptTags?.moduleScript || null,
            'script'
        );
        this.styleInfo = this.addDefaultLanguage(
            config,
            extractStyleTag(this.content, this.html),
            'style'
        );
        this.templateInfo = this.addDefaultLanguage(
            config,
            extractTemplateTag(this.content, this.html),
            'markup'
        );
    };

    const config = configLoader.getConfig(this.getFilePath() || '');
    if (config && !config.loadConfigError) {
        update(config);
    } else {
        update(undefined);
        this.configPromise.then((c) => update(c));
    }
}

